}
</script>
{{ else }}
<script type="application/ld+json">
{
  "@context": "https://schema.org",
  "@type": "BreadcrumbList",
  "itemListElement": [
    {
      "@type": "ListItem",
      "position": 1,
      "name": "Home",
      "item": {{ .Site.BaseURL | jsonify | safeJS }}
    }{{ if and .Parent (not .Parent.IsHome) }},
    {
      "@type": "ListItem",
      "position": 2,
      "name": {{ .Parent.Title | jsonify | safeJS }},
      "item": {{ .Parent.Permalink | jsonify | safeJS }}
    },
    {
      "@type": "ListItem",
      "position": 3,
      "name": {{ .Title | jsonify | safeJS }}
    }{{ else }},
    {
      "@type": "ListItem",
      "position": 2,
      "name": {{ .Title | jsonify | safeJS }}
    }{{ end }}
  ]
}
</script>
<script type="application/ld+json">
{
  "@context": "https://schema.org",
  {{ if and (eq .Section "blog") (ne .Kind "section") }}"@type": "BlogPosting",{{ else if eq .Kind "section" }}"@type": "WebPage",{{ else }}"@type": "Article",{{ end }}
  "headline": {{ .Title | jsonify | safeJS }},
  "description": {{ with .Description }}{{ . | jsonify | safeJS }}{{ else }}{{ .Site.Params.description | jsonify | safeJS }}{{ end }},
  "url": {{ .Permalink | jsonify | safeJS }},
  "mainEntityOfPage": {
    "@type": "WebPage",
    "@id": {{ .Permalink | jsonify | safeJS }}
  },
  "author": {
    "@type": "Organization",
    "name": "Meow Programming Language",
    "url": {{ .Site.BaseURL | jsonify | safeJS }}
  },
  "publisher": {
    "@type": "Organization",
    "name": "Meow Programming Language",
    "url": {{ .Site.BaseURL | jsonify | safeJS }},
    "logo": {
      "@type": "ImageObject",
      "url": {{ printf "%sfavicon.svg" .Site.BaseURL | jsonify | safeJS }}
    }
  },
  "image": {{ printf "%s%s" .Site.BaseURL (default "favicon.svg" .Site.Params.ogpImage) | jsonify | safeJS }}{{ if not .Date.IsZero }},
  "datePublished": {{ .Date.Format "2006-01-02T15:04:05Z07:00" | jsonify | safeJS }}{{ end }}{{ if not .Lastmod.IsZero }},
  "dateModified": {{ .Lastmod.Format "2006-01-02T15:04:05Z07:00" | jsonify | safeJS }}{{ end }}
}
</script>
{{ end }}
